-- ============================================================
-- KOMPLETNÍ IMPORT — variable_costs + fixed_costs + extra_costs
-- Vygenerováno: 2026-06-08T15:15:39.407Z
-- ============================================================

begin;

-- ─── 1. VARIABLE COSTS — 454 řádků, měsíce: 1,2026, 2,2026, 3,2026, 4,2026, 5,2026, 6,2026 ───

delete from variable_costs where month = '1,2026';
delete from variable_costs where month = '2,2026';
delete from variable_costs where month = '3,2026';
delete from variable_costs where month = '4,2026';
delete from variable_costs where month = '5,2026';
delete from variable_costs where month = '6,2026';

on conflict (external_id) do update set
  team_member = excluded.team_member, client = excluded.client, hours = excluded.hours, price = excluded.price,
  task_type = excluded.task_type, date = excluded.date, task_name = excluded.task_name, month = excluded.month;

-- ─── 2. FIXED COSTS — 13 položek, celkem 33758.29 Kč ───

delete from fixed_costs;


-- ─── 3. EXTRA COSTS — 75 řádků, měsíce: 1,2026, 2,2026, 3,2026, 4,2026, 5,2026 ───

delete from extra_costs where month = '1,2026';
delete from extra_costs where month = '2,2026';
delete from extra_costs where month = '3,2026';
delete from extra_costs where month = '4,2026';
delete from extra_costs where month = '5,2026';


-- ─── 4. VERIFIKACE ───────────────────────────────────────

select 'variable_costs' as tabulka, month, count(*) as zaznamu, round(sum(price)::numeric, 0) as kc
  from variable_costs where month in ('1,2026', '2,2026', '3,2026', '4,2026', '5,2026', '6,2026') group by month
union all
select 'extra_costs', month, count(*), round(sum(amount)::numeric, 0)
  from extra_costs where month in ('1,2026', '2,2026', '3,2026', '4,2026', '5,2026') group by month
union all
select 'fixed_costs', '(per month)', count(*), round(sum(amount)::numeric, 0)
  from fixed_costs where active = true
order by 1, 2;

commit;
